parameters.query:
SELECT COALESCE(
  (SELECT cursor_value FROM sync_cursors
   WHERE integration_key = 'gmail_date::' || '{{ $json.mailbox_email }}'),
  to_char(now() - interval '2 days', 'YYYY/MM/DD')
) AS last_sync_date;

parameters.jsCode:
const mailbox = $('Split mailboxes').item.json;
const row = $input.item.json;

// Subtract 1 day from last_sync_date for safety overlap
const d = new Date(row.last_sync_date.replace(/\//g, '-'));
d.setDate(d.getDate() - 1);
const afterDate = d.toISOString().slice(0, 10).replace(/-/g, '/');

return [{
  json: {
    mailbox_id:    mailbox.mailbox_id,
    mailbox_email: mailbox.mailbox_email,
    after_date:    afterDate
  }
}];

const esc = (str) => (str ?? '').replace(/'/g, "''");

const FREEMAIL = new Set([
  'gmail.com','googlemail.com','outlook.com','hotmail.com','hotmail.es',
  'live.com','yahoo.com','yahoo.es','icloud.com','me.com','mac.com',
  'protonmail.com','proton.me','aol.com','zoho.com','mail.com',
  'gmx.com','gmx.es','yandex.com','tutanota.com','fastmail.com'
]);

const ctx = $('Build Gmail query').first().json;
const mailboxEmail = ctx.mailbox_email.toLowerCase();
const mailboxId    = ctx.mailbox_id;

const results = [];

for (const item of $input.all()) {
  const msg = item.json;

  const rawFrom    = msg.From    ?? '';
  const rawTo      = msg.To      ?? '';
  const rawCc      = msg.Cc      ?? msg.CC ?? '';
  const rawSubject = msg.Subject ?? msg.subject ?? '';

  // Robust address parser
  const parseAddresses = (raw, role) => {
    if (!raw) return [];
    return raw.split(/,(?=(?:[^"]*"[^"]*")*[^"]*$)/).map(addr => {
      addr = addr.trim();
      const angleMatch = addr.match(/<([^>]+)>/);
      if (angleMatch) {
        const email = angleMatch[1].trim().toLowerCase();
        const namePart = addr.slice(0, addr.indexOf('<')).replace(/^["'\s]+|["'\s]+$/g, '').trim();
        return { email, name: esc(namePart), role };
      }
      const bareEmail = addr.replace(/^["'\s]+|["'\s]+$/g, '').toLowerCase();
      return { email: bareEmail, name: '', role };
    }).filter(p => p.email && p.email.includes('@'));
  };

  const participants = [
    ...parseAddresses(rawFrom, 'from'),
    ...parseAddresses(rawTo,   'to'),
    ...parseAddresses(rawCc,   'cc')
  ];

  const fromEntry  = participants.find(p => p.role === 'from');
  const fromEmail  = fromEntry?.email ?? '';
  const fromDomain = fromEmail.includes('@') ? fromEmail.split('@')[1] : '';

  const allRecipients = participants
    .filter(p => p.role === 'to' || p.role === 'cc')
    .map(p => p.email);

  let direction;
  if (fromEmail === mailboxEmail) {
    direction = 'team_to_client';
  } else if (allRecipients.includes(mailboxEmail)) {
    direction = 'client_to_team';
  } else {
    direction = 'internal';
  }

  // For team_to_client: resolve from RECIPIENT, not sender
  let resolveEmail, resolveDomain;
  if (direction === 'team_to_client') {
    const extRecipient = participants.find(
      p => (p.role === 'to' || p.role === 'cc') && p.email !== mailboxEmail
    );
    resolveEmail  = extRecipient?.email ?? '';
    resolveDomain = resolveEmail.includes('@') ? resolveEmail.split('@')[1] : '';
  } else {
    resolveEmail  = fromEmail;
    resolveDomain = fromDomain;
  }

  // Freemail: don't resolve by domain (would merge unrelated people)
  if (FREEMAIL.has(resolveDomain)) {
    resolveDomain = '';
  }

  const cleanSubject = rawSubject
    .replace(/^(Re|RE|Fwd|FWD|Fw|FW):\s*/g, '')
    .trim();

  const bodyText = msg.snippet ?? '';

  const sentAt = msg.internalDate
    ? new Date(parseInt(msg.internalDate)).toISOString()
    : new Date().toISOString();

  // Resolve display name (from the person we're resolving against)
  let resolveDisplayName = '';
  if (direction === 'team_to_client') {
    const extRecipient = participants.find(
      p => (p.role === 'to' || p.role === 'cc') && p.email !== mailboxEmail
    );
    resolveDisplayName = extRecipient?.name ?? '';
  } else {
    resolveDisplayName = fromEntry?.name ?? '';
  }
  results.push({
    json: {
      provider_message_id: msg.id,
      provider_thread_id:  msg.threadId,
      internet_message_id: '',
      subject:             esc(cleanSubject),
      raw_subject:         esc(rawSubject),
      snippet:             esc(msg.snippet ?? ''),
      body_text:           esc(bodyText),
      sent_at:             sentAt,
      direction,
      participants,
      from_email:          fromEmail,
      from_domain:         fromDomain,
      resolve_email:       resolveEmail,
      resolve_domain:      resolveDomain,
      mailbox_id:          mailboxId,
      mailbox_email:       mailboxEmail,
      resolve_display_name: resolveDisplayName,
      raw_payload:         JSON.stringify(msg).replace(/'/g, "''")
    }
  });
}

return results;

const allNormalized = $('Normalitza email').all();
const allClients = $input.all();

return allClients.map((clientItem, i) => {
  const normalized = allNormalized[i].json;
  const clientRow = clientItem.json;
  return {
    json: {
      ...normalized,
      client_id: clientRow?.client_id ?? null,
      needs_manual_review: !clientRow?.client_id
    }
  };
});

const allMerged = $('Merge client_id').all();
const allThreads = $input.all();

return allThreads.map((threadItem, i) => {
  const msg = allMerged[i].json;
  const threadRow = threadItem.json;
  return {
    json: { ...msg, thread_id: threadRow.thread_id }
  };
});

const allAttached = $('Attach thread_id').all();
const allMessages = $input.all();

const results = [];
for (let i = 0; i < allMessages.length; i++) {
  const msg = allAttached[i].json;
  const messageRow = allMessages[i].json;
  for (const p of msg.participants) {
    results.push({
      json: {
        message_id: messageRow.message_id,
        thread_id:  msg.thread_id,
        email:      p.email,
        name:       p.name,
        role:       p.role
      }
    });
  }
}
return results;

// Get thread_ids from Expand participants (not from $input which comes from Upsert)
const allParticipants = $('Expand participants').all();
const seen = new Set();
const results = [];
for (const item of allParticipants) {
  const tid = item.json.thread_id;
  if (tid && !seen.has(tid)) {
    seen.add(tid);
    results.push({ json: { thread_id: tid } });
  }
}
return results;

const items = $input.all();
const results = [];

const SKIP_SUBJECT = [
  /^aceptad[oa]:/i, /^rechazad[oa]:/i,
  /^accepted:/i, /^declined:/i, /^tentative:/i,
  /^invitation:/i, /^invitaci[oó]n:/i,
  /^updated invitation/i, /^canceled event/i, /^evento cancelado/i,
  /^out of office/i, /^fuera de (la )?oficina/i,
  /^automatic reply/i, /^respuesta autom[aá]tica/i,
  /^undelivered mail/i, /^delivery status/i, /^mail delivery failed/i,
  /^unsubscribe/i, /has accepted this invitation/i,
  /^nuevo evento:/i, /^new event:/i,
];

const SKIP_SENDERS = [
  /noreply@/i, /no-reply@/i, /no_reply@/i, /donotreply@/i,
  /notifications?@/i, /calendar-notification@google\.com/i,
  /mailer-daemon@/i, /postmaster@/i,
  /^notify@/i, /^alert@/i, /^info@.*\.noreply/i,
];

for (const item of items) {
  const { raw_subject, from_email, body_text } = item.json;

  // Skip per patrons de subject
  if (SKIP_SUBJECT.some(p => p.test(raw_subject ?? ''))) continue;

  // Skip per senders automàtics
  if (SKIP_SENDERS.some(p => p.test(from_email ?? ''))) continue;

  // Skip si body completament buit
  if ((body_text ?? '').trim().length === 0) continue;

  results.push({ json: item.json });
}

return results;

const item = $input.item.json;

const prompt = `Eres un clasificador de emails para un CRM empresarial (gestión de relaciones con clientes).
Decide si este email debe almacenarse en la base de datos o ignorarse.

Asunto: ${(item.raw_subject || '').substring(0, 300)}
De: ${item.from_email || ''}
Dirección: ${item.direction}
Fragmento: ${(item.snippet || '').substring(0, 500)}

Responde SOLO con un JSON válido, sin texto adicional:
{"action": "process" o "skip", "reason": "motivo breve en español"}

Criterios para SKIP:
- Newsletters, marketing, publicidad, promociones
- Notificaciones automáticas de apps o servicios (GitHub, Jira, Trello, Stripe, etc.)
- Emails puramente transaccionales sin contenido de negocio
- Confirmaciones de suscripción, verificaciones de cuenta
- Respuestas automáticas genéricas

Criterios para PROCESS (siempre almacenar):
- Comunicación directa con clientes, proveedores o colaboradores
- Consultas, solicitudes, feedback, propuestas, presupuestos
- Cualquier email con contenido de negocio relevante
- Emails cortos que forman parte de una conversación real entre personas
- En caso de duda, siempre PROCESS

JSON:`;

return [{ json: { ...item, classify_prompt: prompt } }];

const item = $('Prompt').item.json;
const aiOutput = $input.item.json;

const rawText = aiOutput?.output?.[0]?.content?.[0]?.text
  ?? aiOutput?.message?.content
  ?? aiOutput?.choices?.[0]?.message?.content
  ?? '';

let decision;
try {
  const cleaned = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  decision = JSON.parse(cleaned);
} catch {
  // Si falla el parsing, processar per seguretat
  decision = { action: 'process' };
}

if (decision.action === 'skip') return [];

// Treure classify_prompt que ja no cal
const { classify_prompt, ...rest } = item;
return [{ json: rest }];
